function buildAssets(s){
  const nbBornes=Math.max(1,Math.round(s.pdc/2)),bornes=[];
  for(let b=1;b<=nbBornes;b++){
    const pdcPer=Math.round(s.pdc/nbBornes),pdcs=[];
    for(let p=1;p<=pdcPer;p++){
      const conn=(s.conns&&s.conns.length)?s.conns[(p-1)%s.conns.length]:(s.type==='DC'?(p%2?'Combo CCS':'CHAdeMO'):'T2');
      const st=s.state==='off'?'off':(s.state==='err'&&b===1?'err':(p===1&&s.state==='warn'?'warn':'ok'));
      pdcs.push({id:`${s.id}-B${b}-P${p}`,name:`PDC ${b}.${p}`,conn,power:s.power,state:st,energy6m:Math.round(800+Math.random()*4000)});
    }
    const energy6m=pdcs.reduce((a,p)=>a+p.energy6m,0);
    const baseUtil=s.type==='DC'?28+Math.random()*30:12+Math.random()*22;
    const util=Math.round(s.state==='off'?0:s.state==='err'?baseUtil*.3:baseUtil);
    const avail=+(s.state==='off'?0:s.state==='err'?60+Math.random()*15:95+Math.random()*4.7).toFixed(1);
    const sessions6m=Math.round(energy6m/(s.type==='DC'?22:11)),avgSessionKwh=+(energy6m/Math.max(1,sessions6m)).toFixed(1);
    const defaults6m=s.state==='err'?4+Math.floor(Math.random()*4):s.age>5?1+Math.floor(Math.random()*3):Math.floor(Math.random()*2);
    const mtbf=defaults6m?Math.round(182/defaults6m):182,co2=Math.round(energy6m*.06);
    bornes.push({id:`${s.id}-B${b}`,name:`Borne ${b}`,station:s.name,stationId:s.id,net:s.net,type:s.type,power:s.power,state:s.state,age:s.age,
      model:s.model||(s.type==='DC'?'Alpitronic HYC':'Schneider EVlink Pro'),serial:`SN-${s.id.slice(-3)}${b}${Math.floor(Math.random()*900+100)}`,
      installed:`${2018+Math.floor(Math.random()*6)}-0${1+Math.floor(Math.random()*8)}`,warranty:`${2024+Math.floor(Math.random()*4)}-12`,
      energy6m,util,avail,sessions6m,avgSessionKwh,defaults6m,mtbf,co2,lastMaint:`2026-0${3+Math.floor(Math.random()*3)}-${(10+Math.floor(Math.random()*18))}`,
      organes:[{name:'Module de puissance',ref:s.type==='DC'?'PWR-50K':'AC-22K'},{name:'Carte communication OCPP',ref:'OCPP-1.6J'},{name:'Compteur MID',ref:'MID-3PH'},{name:'IMD / DDR type B',ref:'DDR-B-30mA'}],pdcs});
  }
  return {raccordement:{pdl:`PRM ${Math.floor(Math.random()*9e7+1e7)}`,puissance:`${s.power<50?36:250} kVA`,gestionnaire:'Enedis',tarif:s.power<50?'BT < 36 kVA':'BT > 36 kVA'},
    tableau:{ref:`TGBT-${s.id.slice(-3)}`,protections:[{name:'Disjoncteur général',ref:'C160N',calibre:'160 A'},{name:'Parafoudre type 2',ref:'iPRD 40r',calibre:'Type 2'},{name:'Différentiel tête',ref:'Vigi iC60',calibre:'300 mA'}]},bornes};
}
