function powMatch(s){if(!filters.pow)return true;if(filters.pow==='ac')return s.type==='AC';return s.type==='DC'&&s.power>=+filters.pow;}
function condVal(s,f){return {power:s.power,pdc:s.pdc,state:s.state,type:s.type,priority:s.priority,nextDays:daysTo(s.nextVisit),fw:s.fwUpToDate?'oui':'non'}[f];}
function matchCond(s,c){const v=condVal(s,c.field);switch(c.op){case'>':return +v>+c.val;case'<':return +v<+c.val;case'=':return String(v)===String(c.val);case'!=':return String(v)!==String(c.val);}return true;}
function advMatch(s){if(!advFilter.conds.length)return true;const r=advFilter.conds.map(c=>matchCond(s,c));return advFilter.mode==='ET'?r.every(Boolean):r.some(Boolean);}
function filtered(){return STATIONS.filter(s=>{
  if(selectedNet&&s.net!==selectedNet)return false;
  if(filters.state&&s.state!==filters.state)return false;
  if(!powMatch(s))return false;
  if(filters.conn&&s.assets&&!s.assets.bornes.some(b=>b.pdcs.some(p=>p.conn===filters.conn)))return false;
  if(filters.alarm&&!s.alarm)return false;
  if(!advMatch(s))return false;
  if(filters.q){const q=filters.q.toLowerCase();if(!(s.name.toLowerCase().includes(q)||s.city.toLowerCase().includes(q)||s.id.toLowerCase().includes(q)))return false;}
  return true;});}
