function renderStations(){
  const list=filtered();
  const nc=document.getElementById('cntStationsNav');if(nc)nc.textContent=list.length;
  const sc=document.getElementById('stCount');if(sc)sc.textContent=list.length+' station'+(list.length!==1?'s':'');
  const g=id=>document.getElementById(id);
  if(g('stFState')){g('stFState').value=filters.state;g('stFPow').value=filters.pow;g('stFConn').value=filters.conn;g('stFAlarm').checked=filters.alarm;g('stSearch').value=filters.q;}
  const tbody=document.querySelector('#stationsTable tbody');if(!tbody)return;
  const SF={ok:'Disponible',warn:'Occupée',err:'En défaut',off:'Hors service'};
  tbody.innerHTML=list.length?list.map(s=>`<tr style="cursor:pointer" onclick="openStation('${s.id}')">
    <td><span style="display:inline-flex;align-items:center;gap:6px"><span style="width:9px;height:9px;border-radius:50%;background:${STATE_HEX[s.state]};flex-shrink:0;display:inline-block"></span>${SF[s.state]||s.state}</span></td>
    <td class="muted" style="font-size:11.5px">${s.id}</td>
    <td><b>${s.name}</b></td>
    <td>${s.city}</td>
    <td><span class="chip">${s.net}</span></td>
    <td>${s.op}</td>
    <td class="muted">${s.maint}</td>
    <td style="text-align:right">${s.pdc}</td>
    <td style="text-align:right">${s.power} kW</td>
    <td><span class="tag ${s.type==='DC'?'t-info':'t-ok'}" style="font-size:10.5px">${s.type}</span></td>
    <td style="text-align:center">${s.alarm?'<span class="tag t-err" style="font-size:10px">🔔</span>':'<span class="muted">—</span>'}</td>
  </tr>`).join(''):'<tr><td colspan="11" style="text-align:center;padding:30px;color:var(--text-faint)">Aucune station.</td></tr>';
}
function fitToSelection(){const list=filtered();if(!list.length){lmap.setView([46.7,2.4],6);return;}
  if(selectedNet)lmap.fitBounds(L.latLngBounds(list.map(s=>[s.lat,s.lon])).pad(0.12));else lmap.setView([46.7,2.4],6);}
function renderList(list){
  const CAP=180,shown=list.slice(0,CAP);
  stationList.innerHTML=(shown.map(s=>`<div class="list-item ${s.id===selectedId?'sel':''}" data-id="${s.id}">
    <span class="st-dot ${STATE_CLASS[s.state]}" style="margin-top:4px"></span>
    <div style="flex:1"><div class="nm">${s.name} ${s.alarm?'🔔':''}</div>
    <div class="meta">${NET_BY_ID[s.net].name} · <b>${s.type} ${s.power} kW</b> · ${s.pdc} PDC · ${STATE_LABEL[s.state]}</div></div></div>`).join('')
    ||'<div style="padding:30px;text-align:center;color:var(--text-faint)">Aucune station.</div>')
    +(list.length>CAP?`<div style="padding:14px 16px;text-align:center;color:var(--text-faint);font-size:12px">+ ${list.length-CAP} autres — affinez les filtres / choisissez un réseau.</div>`:'');
  stationList.querySelectorAll('.list-item').forEach(el=>el.onclick=()=>openStation(el.dataset.id));
}
function applyFilters(){syncMapControls();renderMap();renderStations();}
const bind=(id,key)=>document.getElementById(id).addEventListener('change',e=>{filters[key]=e.target.type==='checkbox'?e.target.checked:e.target.value;applyFilters();});
bind('fState','state');bind('fPow','pow');bind('fConn','conn');bind('fAlarm','alarm');
document.getElementById('mapSearch').addEventListener('input',e=>{filters.q=e.target.value;applyFilters();});
document.getElementById('fColor').onchange=e=>{colorBy=e.target.value;renderLegend();renderMap();};
document.getElementById('fReset').onclick=()=>{Object.assign(filters,{state:'',pow:'',conn:'',alarm:false,q:''});advFilter={mode:'ET',conds:[]};applyFilters();fitToSelection();};
const stBind=(id,key)=>document.getElementById(id).addEventListener('change',e=>{filters[key]=e.target.type==='checkbox'?e.target.checked:e.target.value;applyFilters();});
stBind('stFState','state');stBind('stFPow','pow');stBind('stFConn','conn');stBind('stFAlarm','alarm');
document.getElementById('stSearch').addEventListener('input',e=>{filters.q=e.target.value;applyFilters();});
document.getElementById('stFReset').onclick=()=>{Object.assign(filters,{state:'',pow:'',conn:'',alarm:false,q:''});advFilter={mode:'ET',conds:[]};applyFilters();fitToSelection();};
document.getElementById('resetView').onclick=()=>{selectedNet?fitToSelection():lmap.setView([46.7,2.4],6);};

document.getElementById('btnExport').onclick=()=>toast('Export GeoJSON / CSV / IRVE (EF-X2) — '+filtered().length+' stations · format ouvert (RV-01)');

/* ---- Filtre avancé ET/OU (GC) ---- */
const ADV_FIELDS=[['power','Puissance (kW)'],['pdc','Nb PDC'],['state','État (ok/warn/err/off)'],['type','Type (AC/DC)'],['priority','Criticité (P1/P2/P3)'],['nextDays','Prochaine visite (jours)'],['fw','Firmware à jour (oui/non)']];
let advDraft=[];
function openAdvModal(){advDraft=advFilter.conds.length?advFilter.conds.map(c=>({...c})):[{field:'nextDays',op:'<',val:'30'}];renderAdvModal();}
function renderAdvModal(){
  const body=`<div class="muted" style="font-size:12.5px">Combinez plusieurs conditions sur les paramètres du parc. Les filtres agissent simultanément sur la carte, la liste et les KPI (EF-15).</div>
  <div style="display:flex;gap:8px;align-items:center"><span style="font-size:12px;font-weight:600">Combiner avec :</span>
    <div class="seg"><button onclick="advMode('ET')" class="${advFilter.mode==='ET'?'on':''}">ET (tout)</button><button onclick="advMode('OU')" class="${advFilter.mode==='OU'?'on':''}">OU (au moins un)</button></div></div>
  <div id="advRows" style="display:grid;gap:8px">`+advDraft.map((c,i)=>`<div style="display:grid;grid-template-columns:1fr 70px 1fr 32px;gap:8px;align-items:center">
    <select onchange="advSet(${i},'field',this.value)">${ADV_FIELDS.map(f=>`<option value="${f[0]}" ${c.field===f[0]?'selected':''}>${f[1]}</option>`).join('')}</select>
    <select onchange="advSet(${i},'op',this.value)">${['>','<','=','!='].map(o=>`<option ${c.op===o?'selected':''}>${o}</option>`).join('')}</select>
    <input value="${c.val}" oninput="advSet(${i},'val',this.value)" placeholder="valeur">
    <button class="btn ghost sm" onclick="advDel(${i})">✕</button></div>`).join('')+`</div>
  <button class="btn ghost sm" onclick="advAdd()" style="justify-self:start">＋ Ajouter une condition</button>`;
  openModal('Filtre avancé — conditions ET / OU', body, `<button class="btn ghost" onclick="advClear()">Tout effacer</button><button class="btn ghost" onclick="closeModal()">Annuler</button><button class="btn" onclick="advApply()">Appliquer (${advDraft.length})</button>`,'');
}
window.advMode=m=>{advFilter.mode=m;renderAdvModal();};
window.advSet=(i,k,v)=>{advDraft[i][k]=v;};
window.advAdd=()=>{advDraft.push({field:'power',op:'>',val:'50'});renderAdvModal();};
window.advDel=i=>{advDraft.splice(i,1);renderAdvModal();};
window.advClear=()=>{advDraft=[];advFilter={mode:advFilter.mode,conds:[]};closeModal();renderMap();fitToSelection();toast('Filtre avancé effacé');};
window.advApply=()=>{advFilter.conds=advDraft.filter(c=>c.val!=='');closeModal();renderMap();fitToSelection();updateAdvChip();toast(advFilter.conds.length+' condition(s) appliquée(s) · '+filtered().length+' stations');};
function updateAdvChip(){document.getElementById('btnAdv').textContent=advFilter.conds.length?`⚙ Filtre avancé (${advFilter.conds.length})`:'⚙ Filtre avancé';}
document.getElementById('btnAdv').onclick=openAdvModal;

/* ---- Groupes de suivi (GC) ---- */
function updateGroupSel(){document.getElementById('grpSel').innerHTML='<option value="">— Groupes de suivi —</option>'+groups.map((g,i)=>`<option value="${i}">★ ${g.name}</option>`).join('');}
document.getElementById('grpSave').onclick=()=>{const n=prompt('Nom du groupe de suivi (sélection + paramètres actuels) :');if(!n)return;
  groups.push({name:n,snap:{filters:{...filters},adv:JSON.parse(JSON.stringify(advFilter)),colorBy,net:selectedNet}});updateGroupSel();toast('Groupe « '+n+' » enregistré ('+filtered().length+' stations)');};
document.getElementById('grpSel').onchange=e=>{const g=groups[+e.target.value];if(!g)return;const sn=g.snap;
  Object.assign(filters,sn.filters);advFilter=JSON.parse(JSON.stringify(sn.adv));colorBy=sn.colorBy;selectedNet=sn.net;
  document.getElementById('fState').value=filters.state;document.getElementById('fPow').value=filters.pow;document.getElementById('fConn').value=filters.conn;document.getElementById('fAlarm').checked=filters.alarm;document.getElementById('mapSearch').value=filters.q;document.getElementById('fColor').value=colorBy;document.getElementById('tenantSel').value=selectedNet;
  updateAdvChip();renderLegend();renderMap();fitToSelection();toast('Groupe « '+g.name+' » chargé');};

/* ============ DRAWER STATION ============ */
const drawer=document.getElementById('drawer');let drawerTab='info';
function openStation(id){const s=STATIONS.find(x=>x.id===id);if(!s)return;selectedId=id;
  document.getElementById('dName').textContent=s.name;
  document.getElementById('dAddr').textContent=`${s.id} · ${NET_BY_ID[s.net].name} · ${s.city}`;
  document.getElementById('dStatusDot').className='st-dot '+STATE_CLASS[s.state];
  document.getElementById('dTags').innerHTML=`<span class="tag ${STATE_TAG[s.state]}">${STATE_LABEL[s.state]}</span><span class="tag ${s.type==='DC'?'t-dc':'t-ac'}">${s.type} · ${s.power} kW</span><span class="tag t-info">${s.pdc} PDC</span>${s.alarm?'<span class="tag t-err">🔔 Alarme</span>':''}`;
  renderDrawer(s);drawer.classList.add('open');lmap.setView([s.lat,s.lon],Math.max(lmap.getZoom(),13),{animate:true});}
document.getElementById('drawerClose').onclick=()=>{drawer.classList.remove('open');selectedId=null;};
document.querySelectorAll('.dtab').forEach(t=>t.onclick=()=>{document.querySelectorAll('.dtab').forEach(x=>x.classList.remove('active'));t.classList.add('active');drawerTab=t.dataset.dt;renderDrawer(STATIONS.find(x=>x.id===selectedId));});
function renderDrawer(s){const body=document.getElementById('drawerBody'),a=s.assets;
  if(drawerTab==='info'){const pdcs=a.bornes.flatMap(b=>b.pdcs),on=pdcs.filter(p=>p.state!=='off'&&p.state!=='err').length;
    body.innerHTML=`<div class="sect"><h5>Synthèse</h5><div class="kv"><span>Réseau</span><span>${NET_BY_ID[s.net].name}</span></div><div class="kv"><span>Opérateur</span><span>${s.op}</span></div><div class="kv"><span>Mainteneur</span><span>${s.maint}</span></div><div class="kv"><span>PDC en service</span><span>${on} / ${pdcs.length}</span></div><div class="kv"><span>Disponibilité 6 mois</span><span>${(96+Math.random()*3.5).toFixed(1)} %</span></div></div>
    <div class="sect"><h5>Raccordement (EF-R1)</h5><div class="kv"><span>PDL / PRM</span><span>${a.raccordement.pdl}</span></div><div class="kv"><span>Puissance souscrite</span><span>${a.raccordement.puissance}</span></div><div class="kv"><span>Gestionnaire</span><span>${a.raccordement.gestionnaire}</span></div></div>
    <div class="sect"><h5>Suivi &amp; maintenance</h5><div class="kv"><span>Criticité</span><span>${PRIO_LABEL[s.priority]}</span></div><div class="kv"><span>Firmware</span><span>${s.firmware} ${s.fwUpToDate?'✓ à jour':'⚠️ obsolète'}</span></div><div class="kv"><span>Dernière visite</span><span>${fmtD(s.lastVisit)}</span></div><div class="kv"><span>Prochaine visite</span><span>${fmtD(s.nextVisit)} (${daysTo(s.nextVisit)} j)</span></div></div>
    <div class="sect"><h5>Vieillissement (EF-R4)</h5>${s.age>5?'<div class="chip t-warn" style="border:none">⚠️ Matériel en fin de vie ('+s.age.toFixed(1)+' ans)</div>':'<div class="chip t-ok" style="border:none">✓ Aucune alerte</div>'}</div>
    <div class="sect" style="border:none"><button class="btn sm" onclick="ticketFromStation('${s.id}')">＋ Créer un ticket</button></div>`;
  } else if(drawerTab==='assets'){
    body.innerHTML=`<div class="sect"><h5>Tableau ${a.tableau.ref}</h5>${a.tableau.protections.map(p=>`<div class="kv"><span>${p.name}</span><span>${p.ref} · ${p.calibre}</span></div>`).join('')}</div>
    ${a.bornes.map(b=>`<div class="sect"><h5>${b.name} — ${b.model}</h5><div class="kv"><span>N° série</span><span>${b.serial}</span></div><div class="kv"><span>Pose / Garantie</span><span>${b.installed} → ${b.warranty}</span></div>
      <div style="margin-top:8px;font-size:12px;color:var(--text-soft)">Organes</div>${b.organes.map(o=>`<div class="kv"><span style="padding-left:12px">↳ ${o.name}</span><span>${o.ref}</span></div>`).join('')}
      <div style="margin-top:8px;font-size:12px;color:var(--text-soft)">PDC</div>${b.pdcs.map(p=>`<div class="kv"><span style="padding-left:12px"><span class="st-dot ${STATE_CLASS[p.state]}" style="display:inline-block;margin-right:6px"></span>${p.name} (${p.conn})</span><span>${p.power} kW</span></div>`).join('')}</div>`).join('')}`;
  } else if(drawerTab==='gmao'){const tk=TICKETS.filter(t=>t.stationId===s.id);
    body.innerHTML=`<div class="sect" style="border:none"><h5>Tickets rattachés (EF-M4)</h5>${tk.length?tk.map(t=>`<div style="padding:11px;border:1px solid var(--border);border-radius:9px;margin-bottom:9px;cursor:pointer" onclick="openTicket('${t.ref}')"><div style="display:flex;justify-content:space-between"><b>${t.ref}</b><span class="tag ${SLA_TAG[slaState(t)]}">SLA ${slaState(t)}</span></div><div style="font-size:12.5px;margin-top:3px">${t.title}</div><div class="muted" style="font-size:12px;margin-top:4px">${TYPE_LABEL[t.type]} · ${CRIT_LABEL[t.crit]} · ${t.statut}</div></div>`).join(''):'<div class="muted">Aucun ticket.</div>'}<button class="btn sm" onclick="ticketFromStation('${s.id}')">＋ Créer un ticket</button></div>`;
  } else if(drawerTab==='dyn'){const pdcs=a.bornes.flatMap(b=>b.pdcs);
    body.innerHTML=`<div class="sect"><h5>État temps réel (EF-D2)</h5>${pdcs.slice(0,8).map(p=>`<div class="kv"><span><span class="st-dot ${STATE_CLASS[p.state]}" style="display:inline-block;margin-right:6px"></span>${p.name}</span><span>${STATE_LABEL[p.state]}</span></div>`).join('')}</div>
    <div class="sect"><h5>Énergie</h5><div class="kv"><span>Mois en cours</span><span class="muted">N/D</span></div><div class="kv"><span>6 derniers mois</span><span class="muted">N/D</span></div></div>
    <div class="sect"><h5>Alarmes (EF-D4)</h5>${s.alarm?`<div class="chip t-err" style="border:none;margin-bottom:8px">🔔 Défaut — F-019</div><button class="btn sm" onclick="ticketFromStation('${s.id}')">＋ Générer un ticket depuis l'alarme</button>`:'<div class="chip t-ok" style="border:none">✓ Aucune alarme</div>'}</div>`;
  } else {
    body.innerHTML='<div class="sect"><p class="muted" style="padding:12px 0">Historique non disponible — données temps réel à connecter.</p></div>';
  }
}
let histP='mois';
window.setHist=p=>{histP=p;const s=STATIONS.find(x=>x.id===selectedId);if(s)renderDrawer(s);};
window.openStation=openStation;
window.ticketFromStation=id=>{const s=STATIONS.find(x=>x.id===id);openNewTicket(s);};

/* ============ RÉFÉRENTIEL (réseau→station, lazy) ============ */
function renderRefTree(){
  const tree=document.getElementById('refTree');
  const nets=selectedNet?NETWORKS.filter(n=>n.id===selectedNet):NETWORKS;
  tree.innerHTML=nets.map(n=>`<div class="tnode"><div class="tlabel" data-net="${n.id}"><span class="tw">▶</span><span class="tico">🏢</span><span class="tnm">${n.name}</span> <span class="tsub">· ${STATIONS.filter(s=>s.net===n.id).length} stations</span></div><div class="tchildren" data-netkids="${n.id}"></div></div>`).join('');
  tree.querySelectorAll('[data-net]').forEach(el=>el.onclick=()=>{const id=el.dataset.net,kids=tree.querySelector(`[data-netkids="${id}"]`),tw=el.querySelector('.tw');
    if(!kids.dataset.built){kids.innerHTML=STATIONS.filter(s=>s.net===id).slice(0,120).map(s=>`<div class="tnode"><div class="tlabel" data-exp="${s.id}"><span class="tw">▶</span><span class="tico">📍</span><span class="tnm">${s.name}</span></div><div class="tchildren" data-kids="${s.id}"></div></div>`).join('')+(STATIONS.filter(s=>s.net===id).length>120?'<div class="muted" style="padding:6px 9px;font-size:11px">+ autres stations…</div>':'');kids.dataset.built='1';bindStationNodes(kids);}
    kids.classList.toggle('open');tw.classList.toggle('open');});
  showRefDetail(STATIONS.find(s=>s.net===nets[0].id));
}
function bindStationNodes(root){root.querySelectorAll('[data-exp]').forEach(el=>el.onclick=e=>{e.stopPropagation();
  const sid=el.dataset.exp,kids=root.querySelector(`[data-kids="${sid}"]`),tw=el.querySelector('.tw');
  if(!kids.dataset.built){kids.innerHTML=stationSubtree(STATIONS.find(s=>s.id===sid));kids.dataset.built='1';bindSubtree(kids);}
  kids.classList.toggle('open');tw.classList.toggle('open');showRefDetail(STATIONS.find(s=>s.id===sid));
  root.querySelectorAll('.tlabel').forEach(x=>x.classList.remove('on'));el.classList.add('on');});}
function stationSubtree(s){const a=s.assets;
  return `<div class="tlabel"><span class="tw" style="opacity:0">▶</span><span class="tico">🔌</span>Raccordement <span class="tsub">${a.raccordement.pdl}</span></div>
  <div class="tnode"><div class="tlabel" data-toggle><span class="tw">▶</span><span class="tico">🗄️</span>Tableau ${a.tableau.ref}</div><div class="tchildren">${a.tableau.protections.map(p=>`<div class="tlabel"><span class="tw" style="opacity:0">▶</span><span class="tico">🛡️</span>${p.name} <span class="tsub">${p.ref}</span></div>`).join('')}</div></div>
  ${a.bornes.map(b=>`<div class="tnode"><div class="tlabel" data-toggle data-ref-b="${s.id}|${b.id}"><span class="tw">▶</span><span class="tico">⚡</span>${b.name} <span class="tsub">${b.model}</span></div><div class="tchildren">${b.organes.map(o=>`<div class="tlabel"><span class="tw" style="opacity:0">▶</span><span class="tico">🔩</span>${o.name} <span class="tsub">${o.ref}</span></div>`).join('')}${b.pdcs.map(p=>`<div class="tlabel"><span class="tw" style="opacity:0">▶</span><span class="tico">🔋</span>${p.name} <span class="tsub">${p.conn} · ${p.power} kW</span></div>`).join('')}</div></div>`).join('')}`;}
function bindSubtree(root){root.querySelectorAll('[data-toggle]').forEach(el=>el.onclick=e=>{e.stopPropagation();const tw=el.querySelector('.tw'),kids=el.nextElementSibling;if(kids&&kids.classList.contains('tchildren')){kids.classList.toggle('open');tw.classList.toggle('open');}const bid=el.dataset.refB;if(bid){const[sid,bbid]=bid.split('|');showRefBorne(STATIONS.find(s=>s.id===sid),bbid);}root.querySelectorAll('.tlabel').forEach(x=>x.classList.remove('on'));el.classList.add('on');});}
const statc=(l,v)=>`<div class="card stat" style="box-shadow:none"><div class="lab">${l}</div><div class="val" style="font-size:22px">${v}</div></div>`;
function showRefDetail(s){const a=s.assets;document.getElementById('refDetail').innerHTML=`
  <div style="display:flex;justify-content:space-between;flex-wrap:wrap;gap:10px"><div><h2 style="font-size:19px">${s.name}</h2><div class="muted">${s.id} · ${NET_BY_ID[s.net].name}</div></div><div style="display:flex;gap:6px"><span class="tag ${STATE_TAG[s.state]}">${STATE_LABEL[s.state]}</span><span class="tag ${s.type==='DC'?'t-dc':'t-ac'}">${s.type} ${s.power} kW</span></div></div>
  <div class="grid cols-3" style="padding:18px 0 0;gap:12px">${statc('Bornes',a.bornes.length)}${statc('PDC',a.bornes.flatMap(b=>b.pdcs).length)}${statc('Âge moyen',s.age.toFixed(1)+' ans')}</div>
  <h5 style="margin:18px 0 8px;font-size:11px;text-transform:uppercase;letter-spacing:.6px;color:var(--text-faint)">Attributs (EF-R2)</h5>
  <table><tbody><tr><td class="muted">Opérateur</td><td><b>${s.op}</b></td><td class="muted">Mainteneur</td><td><b>${s.maint}</b></td></tr><tr><td class="muted">PDL</td><td><b>${a.raccordement.pdl}</b></td><td class="muted">Coordonnées</td><td><b>${s.lat.toFixed(4)}, ${s.lon.toFixed(4)}</b></td></tr></tbody></table>
  <div style="margin-top:16px;display:flex;gap:8px"><button class="btn ghost sm" onclick="document.querySelector('[data-view=map]').click();openStation('${s.id}')">🗺️ Voir sur la carte</button><button class="btn ghost sm" onclick="ticketFromStation('${s.id}')">🎫 Créer un ticket</button></div>`;}
function showRefBorne(s,bid){const b=s.assets.bornes.find(x=>x.id===bid);document.getElementById('refDetail').innerHTML=`
  <div><h2 style="font-size:19px">${b.name}</h2><div class="muted">${s.name} · ${b.model}</div></div>
  <h5 style="margin:18px 0 8px;font-size:11px;text-transform:uppercase;letter-spacing:.6px;color:var(--text-faint)">Caractéristiques (EF-R2/R3)</h5>
  <table><tbody><tr><td class="muted">Modèle</td><td><b>${b.model}</b></td><td class="muted">N° série</td><td><b>${b.serial}</b></td></tr><tr><td class="muted">Pose</td><td><b>${b.installed}</b></td><td class="muted">Garantie</td><td><b>${b.warranty}</b></td></tr></tbody></table>
  <h5 style="margin:18px 0 8px;font-size:11px;text-transform:uppercase;letter-spacing:.6px;color:var(--text-faint)">Organes</h5><table><tbody>${b.organes.map(o=>`<tr><td>${o.name}</td><td><b>${o.ref}</b></td></tr>`).join('')}</tbody></table>
  <h5 style="margin:18px 0 8px;font-size:11px;text-transform:uppercase;letter-spacing:.6px;color:var(--text-faint)">PDC</h5><table><tbody>${b.pdcs.map(p=>`<tr><td><span class="st-dot ${STATE_CLASS[p.state]}" style="display:inline-block;margin-right:6px"></span>${p.name}</td><td>${p.conn}</td><td><b>${p.power} kW</b></td></tr>`).join('')}</tbody></table>`;}

/* ============ GED ============ */
let gedSel={type:'net',id:NETWORKS[0].id};
function renderGedTree(){
  const tree=document.getElementById('gedTree');const nets=selectedNet?NETWORKS.filter(n=>n.id===selectedNet):NETWORKS;
  tree.innerHTML=nets.map(n=>`<div class="tnode"><div class="tlabel" data-gnet="${n.id}"><span class="tw">▶</span><span class="tico">🏢</span><span class="tnm">${n.name}</span> <span class="tsub">· réseau</span></div><div class="tchildren" data-gkids="${n.id}"></div></div>`).join('');
  tree.querySelectorAll('[data-gnet]').forEach(el=>el.onclick=()=>{const id=el.dataset.gnet,kids=tree.querySelector(`[data-gkids="${id}"]`),tw=el.querySelector('.tw');
    if(!kids.dataset.built){kids.innerHTML=STATIONS.filter(s=>s.net===id).slice(0,80).map(s=>`<div class="tlabel" data-gsta="${s.id}"><span class="tw" style="opacity:0">▶</span><span class="tico">📍</span>${s.name}</div>`).join('');kids.dataset.built='1';kids.querySelectorAll('[data-gsta]').forEach(e2=>e2.onclick=ev=>{ev.stopPropagation();gedSel={type:'sta',id:e2.dataset.gsta};markGed(e2);renderGedList();});}
    kids.classList.toggle('open');tw.classList.toggle('open');gedSel={type:'net',id};markGed(el);renderGedList();});
  renderGedList();
}
function markGed(el){document.querySelectorAll('#gedTree .tlabel').forEach(x=>x.classList.remove('on'));el.classList.add('on');}
function renderGedList(){
  const head=document.getElementById('gedHead'),listEl=document.getElementById('gedList');let docs=[],title='';
  if(gedSel.type==='net'){const n=NET_BY_ID[gedSel.id];title=`Réseau ${n.name} — documents`;docs=NET_DOCS[gedSel.id].map(d=>({...d,inh:false}));}
  else{const s=STATIONS.find(x=>x.id===gedSel.id);title=`${s.name} — documents`;docs=[...NET_DOCS[s.net].map(d=>({...d,inh:true})),...stationDocs(s).map(d=>({...d,inh:false}))];}
  head.textContent=title;
  listEl.innerHTML=`<div style="padding:12px 14px;display:flex;gap:8px;border-bottom:1px solid var(--border)"><button class="btn sm">⬆ Téléverser</button><button class="btn ghost sm">＋ Nouveau dossier</button><div class="tb-spacer" style="flex:1"></div><span class="muted" style="font-size:12px;align-self:center">${docs.length} documents · version active + archives</span></div>`
    +docs.map((d,i)=>{const v=2+(i%3);return `<div><div class="doc"><div class="fico" style="background:${DOC_CATS[d.c]}">${d.c[0]}</div><div style="flex:1"><b>${d.n}</b> <span class="tag t-ok" style="font-size:9.5px">v${v} active</span> ${d.inh?'<span class="inherit" title="Hérité du réseau">hérité réseau</span>':''}<div class="muted" style="font-size:12px">${d.c} · ${d.size} · ${v} versions archivées</div></div><span class="muted" style="font-size:12px;width:90px;text-align:right">${d.date}</span><button class="btn ghost sm" onclick="this.closest('div').parentElement.querySelector('.arch').style.display=this.closest('div').parentElement.querySelector('.arch').style.display==='block'?'none':'block'">Versions</button><button class="btn ghost sm">Ouvrir</button></div>
      <div class="arch" style="display:none;padding:0 14px 10px 62px;background:#fafcfb">${Array.from({length:v},(_,k)=>`<div style="display:flex;gap:10px;font-size:12px;padding:4px 0;border-bottom:1px dashed var(--border)"><span class="muted">v${v-1-k}</span><span style="flex:1">${d.n.replace(/\.(\w+)$/,'_v'+(v-1-k)+'.$1')}</span><span class="muted">archivé · 202${4+(k%2)}-0${1+k%8}</span><span style="color:var(--primary);cursor:pointer">restaurer</span></div>`).join('')}</div></div>`;}).join('');
}

/* ============ GMAO TICKETS ============ */
const gf={statut:'',type:'',crit:'',sla:'',scope:''};
function tkFiltered(){return TICKETS.filter(t=>{
  if(selectedNet&&t.net!==selectedNet)return false;
  if(gf.scope==='open'&&!isOpen(t))return false;
  if(gf.scope==='encours'&&t.statut!=='en cours')return false;
  if(gf.scope==='gtr'&&!(isOpen(t)&&slaState(t)==='dépassé'))return false;
  if(gf.scope==='clos'&&isOpen(t))return false;
  if(gf.statut&&t.statut!==gf.statut)return false;
  if(gf.type&&t.type!==gf.type)return false;
  if(gf.crit&&t.crit!==gf.crit)return false;
  if(gf.sla&&slaState(t)!==gf.sla)return false;
  return true;});}
function setScope(sc){gf.scope=gf.scope===sc?'':sc;renderGMAO();}
window.setScope=setScope;
function scard(l,v,ico,sub,dir,sc){return `<div class="card stat clk ${gf.scope===sc?'active':''}" onclick="setScope('${sc}')"><div class="lab">${ico} ${l}</div><div class="val">${v}</div><div class="sub ${dir}">${sub}</div></div>`;}
function renderGMAO(){
  const base=selectedNet?TICKETS.filter(t=>t.net===selectedNet):TICKETS;
  const open=base.filter(isOpen),enCours=base.filter(t=>t.statut==='en cours'),dep=base.filter(t=>isOpen(t)&&slaState(t)==='dépassé'),clos=base.filter(t=>!isOpen(t));
  document.getElementById('gmaoStats').innerHTML=[
    scard('Tickets ouverts',open.length,'🎫','dont '+base.filter(t=>t.statut==='nouveau').length+' nouveaux','','open'),
    scard('En cours',enCours.length,'🔧','traitement actif','','encours'),
    scard('Dépassement GTR',dep.length,'⏱️','SLA non tenu',dep.length?'down':'','gtr'),
    scard('Clôturés',clos.length,'✅','backlog '+open.length+' ouverts','','clos'),
  ].join('');
  renderTk();
}
function renderTk(){
  const rows=tkFiltered().sort((a,b)=>b.created-a.created);
  document.querySelector('#tkTable tbody').innerHTML=rows.map(t=>{const sl=slaState(t);return `<tr class="tkrow crit-${t.crit}" data-ref="${t.ref}" style="cursor:pointer">
    <td><b>${t.ref}</b></td><td>${t.title}</td><td><span class="tag ${t.type==='preventif'?'t-info':t.type==='curatif'?'t-warn':'t-err'}">${TYPE_LABEL[t.type]}</span></td>
    <td><span class="tag ${CRIT_TAG[t.crit]}">${CRIT_LABEL[t.crit]}</span></td><td>${t.statut}</td>
    <td>${t.station}<div class="muted" style="font-size:11.5px">${t.equip}</div></td><td>${t.tech||'<span class="muted">—</span>'}</td>
    <td style="font-size:12px">${isOpen(t)?cd(t.gti):'—'}</td><td style="font-size:12px">${isOpen(t)?cd(t.gtr):'—'}</td>
    <td><span class="tag ${SLA_TAG[sl]}">${sl}</span></td></tr>`;}).join('')||'<tr><td colspan="10" style="text-align:center;color:var(--text-faint);padding:24px">Aucun ticket.</td></tr>';
  document.querySelectorAll('#tkTable tbody tr[data-ref]').forEach(tr=>tr.onclick=()=>openTicket(tr.dataset.ref));
}
['gfStatut','gfType','gfCrit','gfSla'].forEach(id=>document.getElementById(id).onchange=e=>{gf[id.replace('gf','').toLowerCase()]=e.target.value;renderTk();});
document.getElementById('gfSaved').onclick=()=>{gf.statut='';gf.type='';gf.crit='';gf.sla='';gf.scope='gtr';['gfStatut','gfType','gfCrit','gfSla'].forEach(i=>document.getElementById(i).value='');renderGMAO();toast('Vue enregistrée : tickets en dépassement GTR (EF-M14)');};
const statCard=(l,v,ico,sub,dir)=>`<div class="card stat"><div class="lab">${ico} ${l}</div><div class="val">${v}</div><div class="sub ${dir}">${sub}</div></div>`;

/* Ticket detail modal + lifecycle */
function openTicket(ref){const t=TICKETS.find(x=>x.ref===ref);if(!t)return;const sl=slaState(t),ci=LIFECYCLE.indexOf(t.statut);
  const steps=LIFECYCLE.slice(0,5).map((st,i)=>`<div class="step ${i<ci?'done':i===ci?'cur':''}"><div class="b">${i<ci?'✓':i+1}</div>${st}</div>${i<4?'<div class="line"></div>':''}`).join('');
  const acts=isOpen(t)?`${t.statut==='nouveau'||t.statut==='assigné'?'<button class="btn sm" onclick="tkAct(\''+ref+'\',\'en cours\')">Prendre en charge</button>':''}
     ${t.statut==='en cours'?'<button class="btn ghost sm" onclick="tkAct(\''+ref+'\',\'en attente\')">Mettre en attente</button><button class="btn sm" onclick="tkAct(\''+ref+'\',\'résolu\')">Résoudre</button>':''}
     ${t.statut==='en attente'?'<button class="btn sm" onclick="tkAct(\''+ref+'\',\'en cours\')">Reprendre</button>':''}
     <button class="btn sm" onclick="closeTicketForm('${ref}')">Clôturer…</button>`:'<button class="btn ghost sm" onclick="tkAct(\''+ref+'\',\'en cours\')">Rouvrir</button>';
  openModal(`Ticket ${t.ref}`, `
    <div><div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:4px"><span class="tag ${CRIT_TAG[t.crit]}">${CRIT_LABEL[t.crit]}</span><span class="tag ${t.type==='preventif'?'t-info':t.type==='curatif'?'t-warn':'t-err'}">${TYPE_LABEL[t.type]}</span><span class="tag ${SLA_TAG[sl]}">SLA ${sl}</span><span class="chip">Origine : ${t.src}</span></div>
    <h3 style="font-size:16px;margin:6px 0">${t.title}</h3><div class="muted" style="font-size:12.5px">${t.station} · ${t.equip} · ${NET_BY_ID[t.net].name}</div></div>
    <div><h5 style="font-size:11px;text-transform:uppercase;color:var(--text-faint);margin-bottom:6px">Cycle de vie (EF-M3)</h5><div class="stepper">${steps}</div></div>
    <div class="sla"><div class="clock"><div class="t">GTI — prise en charge</div><div class="v" style="color:${isOpen(t)&&NOW>t.gti?'var(--err)':'var(--text)'}">${isOpen(t)?cd(t.gti):'tenu'}</div><div class="muted" style="font-size:11px">échéance ${t.gti.toLocaleString('fr-FR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}</div></div>
      <div class="clock"><div class="t">GTR — rétablissement</div><div class="v" style="color:${isOpen(t)&&NOW>t.gtr?'var(--err)':'var(--text)'}">${isOpen(t)?cd(t.gtr):(t.closedAt<=t.gtr?'tenu':'dépassé')}</div><div class="muted" style="font-size:11px">échéance ${t.gtr.toLocaleString('fr-FR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}</div></div></div>
    <div><h5 style="font-size:11px;text-transform:uppercase;color:var(--text-faint);margin-bottom:6px">Détails</h5>
      <div class="kv"><span>Technicien assigné</span><span>${t.tech||'—'}</span></div><div class="kv"><span>Créé le</span><span>${t.created.toLocaleString('fr-FR')}</span></div><div class="kv"><span>Statut</span><span>${t.statut}</span></div></div>`,
    `<div style="margin-right:auto" class="muted" style="font-size:12px;align-self:center">Actions (EF-M3, RBAC)</div>${acts}`,'wide');
}
window.openTicket=openTicket;
window.tkAct=(ref,st)=>{const t=TICKETS.find(x=>x.ref===ref);t.statut=st;if(st==='nouveau')t.closedAt=null;closeModal();renderGMAO();updateCounts();toast('Ticket '+ref+' → '+st);};
window.closeTicketForm=ref=>{openModal('Clôture — '+ref,`
  <div class="field"><label>Compte-rendu d'intervention *</label><textarea id="clRep" rows="3" placeholder="Diagnostic, actions réalisées…"></textarea></div>
  <div><h5 style="font-size:11px;text-transform:uppercase;color:var(--text-faint);margin-bottom:6px">Check-list de conformité (EF-M8)</h5>
    <label class="check"><input type="checkbox" class="clChk"> Remise en service vérifiée</label><label class="check"><input type="checkbox" class="clChk"> Test de charge OK</label><label class="check"><input type="checkbox" class="clChk"> Zone sécurisée / nettoyée</label></div>
  <div class="field"><label>Temps passé (min)</label><input id="clTime" type="number" value="90"></div>
  <div class="field"><label>Pièce remplacée (traçabilité RMA — EF-M10)</label><input placeholder="ancien N° → nouveau N° de série"></div>
  <div class="muted" style="font-size:12px">📷 Photos avant/après + signature requises. La clôture est bloquée tant que le formulaire est incomplet (EF-M9).</div>`,
  `<button class="btn ghost" onclick="closeModal()">Annuler</button><button class="btn" id="clOk">Clôturer le ticket</button>`,'');
  setTimeout(()=>{document.getElementById('clOk').onclick=()=>{const rep=document.getElementById('clRep').value.trim();const chk=[...document.querySelectorAll('.clChk')].every(c=>c.checked);
    if(!rep||!chk){toast('⛔ Formulaire incomplet — clôture impossible (EF-M9)');return;}
    const t=TICKETS.find(x=>x.ref===ref);t.statut='clôturé';t.closedAt=NOW;closeModal();renderGMAO();updateCounts();toast('Ticket '+ref+' clôturé · tracé au journal (EF-A6)');};},30);
};
function openNewTicket(s){openModal('Nouveau ticket (EF-M4)',`
  <div class="field"><label>Station</label><select id="ntSta">${(selectedNet?STATIONS.filter(x=>x.net===selectedNet):STATIONS).slice(0,200).map(x=>`<option ${s&&x.id===s.id?'selected':''} value="${x.id}">${x.name}</option>`).join('')}</select></div>
  <div class="field"><label>Équipement</label><select><option>Station (TGBT)</option><option>Borne 1</option><option>Borne 2</option><option>Point de charge</option></select></div>
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px"><div class="field"><label>Type</label><select id="ntType"><option value="curatif">Curatif</option><option value="preventif">Préventif</option><option value="depannage">Dépannage</option></select></div>
  <div class="field"><label>Criticité</label><select id="ntCrit"><option value="critique">Critique</option><option value="majeur">Majeur</option><option value="mineur">Mineur</option></select></div></div>
  <div class="field"><label>Titre / objet</label><input id="ntTitle" placeholder="Décrire le problème…"></div>
  <div class="muted" style="font-size:12px">Les échéances GTI/GTR seront calculées automatiquement selon la criticité et le contrat (EF-M11/M12).</div>`,
  `<button class="btn ghost" onclick="closeModal()">Annuler</button><button class="btn" id="ntOk">Créer le ticket</button>`,'');
  setTimeout(()=>{document.getElementById('ntOk').onclick=()=>{const st=STATIONS.find(x=>x.id===document.getElementById('ntSta').value);
    const t=mkTicket(st,document.getElementById('ntType').value,document.getElementById('ntCrit').value,'nouveau',0,'manuel',document.getElementById('ntTitle').value||'Nouveau ticket');
    TICKETS.unshift(t);closeModal();renderGMAO();updateCounts();toast('Ticket '+t.ref+' créé');};},30);
}
document.getElementById('btnNewTk').onclick=()=>openNewTicket(null);

/* ============ PLANNING ============ */
function renderAgenda(){
  const days=['Lun 15','Mar 16','Mer 17','Jeu 18','Ven 19','Sam 20','Dim 21'];
  const open=TICKETS.filter(t=>isOpen(t)&&t.tech&&(!selectedNet||t.net===selectedNet));
  const grid={};TECHS.forEach(tc=>grid[tc.name]=Array.from({length:7},()=>[]));
  open.forEach(t=>{if(!grid[t.tech])return;const d=Math.abs((t.ref.charCodeAt(3)+t.ref.charCodeAt(4))%7);grid[t.tech][d].push(t);});
  document.getElementById('agendaTable').innerHTML=`<thead><tr><th class="tcol">Technicien</th>${days.map(d=>`<th>${d}</th>`).join('')}</tr></thead><tbody>
  ${TECHS.map(tc=>`<tr><td class="tcol">${tc.name}<div class="muted" style="font-size:11px;font-weight:400">${tc.type} · charge ${tc.load}%</div></td>
    ${grid[tc.name].map(evts=>`<td>${evts.slice(0,3).map(t=>`<div class="evt ${t.type}" onclick="openTicket('${t.ref}')" title="${t.title}">${t.ref} · ${t.station.split(' ')[0]}</div>`).join('')}</td>`).join('')}</tr>`).join('')}</tbody>`;
}
document.getElementById('btnPlanNew').onclick=()=>openNewTicket(null);

/* ============ ÉCHÉANCIER ============ */
function renderEch(){
  const list=ECHEANCES.filter(e=>!selectedNet||e.net===selectedNet);
  document.getElementById('echStats').innerHTML=[
    statCard('En retard',list.filter(e=>e.status==='en retard').length,'🔴','à traiter en priorité','down'),
    statCard('Dues (< 15 j)',list.filter(e=>e.status==='due').length,'🟠','à planifier',''),
    statCard('À venir',list.filter(e=>e.status==='à venir').length,'🟢','sous surveillance',''),
  ].join('');
  document.querySelector('#echTable tbody').innerHTML=list.map((e,i)=>`<tr>
    <td><b>${e.equip}</b></td><td>${e.station}<div class="muted" style="font-size:11.5px">${NET_BY_ID[e.net].name}</div></td>
    <td><span class="tag ${e.type==='Préventif'?'t-info':'t-warn'}">${e.type}</span></td>
    <td>${e.last.toLocaleDateString('fr-FR')}</td><td><b>${e.due.toLocaleDateString('fr-FR')}</b></td>
    <td>${e.daysLeft<0?'<span style="color:var(--err);font-weight:700">'+e.daysLeft+' j</span>':e.daysLeft+' j'}</td>
    <td><span class="tag ${e.status==='en retard'?'t-err':e.status==='due'?'t-warn':'t-ok'}">${e.status}</span></td>
    <td>${e.planned?'<span class="muted">planifié ✓</span>':`<button class="btn sm" onclick="planEch(${i})">Planifier</button>`}</td></tr>`).join('');
}
window.planEch=i=>{const list=ECHEANCES.filter(e=>!selectedNet||e.net===selectedNet);const e=list[i];e.planned=true;
  const s=STATIONS.find(x=>x.name===e.station)||pick(STATIONS);TICKETS.unshift(mkTicket(s,'preventif','mineur','assigné',0,'préventif',e.equip));
  renderEch();updateCounts();renderGMAO();toast('Intervention planifiée + ticket créé (EF-M25)');};

/* ============ TOURNÉES DE MAINTENANCE (GC) ============ */
function distKm(a,b){const Rr=6371,dLa=(b[0]-a[0])*Math.PI/180,dLo=(b[1]-a[1])*Math.PI/180,l1=a[0]*Math.PI/180,l2=b[0]*Math.PI/180;const h=Math.sin(dLa/2)**2+Math.cos(l1)*Math.cos(l2)*Math.sin(dLo/2)**2;return 2*Rr*Math.asin(Math.sqrt(h));}
let cityCentroids=null, tourResult=[], tmap=null, tCircle=null, tMarkers=null, tCenterMk=null, tourCenter=null, tourRad=20;
function buildCities(){const m={};STATIONS.forEach(s=>{const k=s.city||s.name;(m[k]||(m[k]={lat:0,lon:0,n:0,net:s.net}));m[k].lat+=s.lat;m[k].lon+=s.lon;m[k].n++;});
  cityCentroids=Object.entries(m).map(([k,v])=>({city:k,lat:v.lat/v.n,lon:v.lon/v.n,n:v.n,net:v.net})).sort((a,b)=>b.n-a.n);}
function initTournee(){
  if(!cityCentroids)buildCities();
  const sel=document.getElementById('tourCenter');
  if(sel.dataset.net!==selectedNet||!sel.options.length){
    const list=cityCentroids.filter(c=>!selectedNet||c.net===selectedNet).slice(0,80);
    sel.innerHTML=list.map(c=>`<option value="${c.city}">${c.city} (${c.n} borne${c.n>1?'s':''})</option>`).join(''); sel.dataset.net=selectedNet;
  }
  if(!tmap){tmap=L.map('tourMiniMap',{zoomControl:true}).setView([49.18,-0.37],9);
    L.tileLayer(G+'image/png&LAYER=GEOGRAPHICALGRIDSYSTEMS.PLANIGNV2&TILEMATRIX={z}&TILEROW={y}&TILECOL={x}',{minZoom:5,maxZoom:18,attribution:'© IGN'}).addTo(tmap);}
  setTimeout(()=>tmap.invalidateSize(),140);
  runTournee();
}
function runTournee(){
  const cname=document.getElementById('tourCenter').value,rad=+document.getElementById('tourRadius').value,win=+document.getElementById('tourWin').value;
  const c=cityCentroids.find(x=>x.city===cname); if(!c)return;
  tourCenter=[c.lat,c.lon];tourRad=rad;
  tourResult=STATIONS.filter(s=>(!selectedNet||s.net===selectedNet)&&daysTo(s.nextVisit)<=win).map(s=>({s,d:distKm(tourCenter,[s.lat,s.lon])})).filter(o=>o.d<=rad).sort((a,b)=>a.d-b.d);
  const km=tourResult.reduce((a,o,i)=>a+(i?distKm([tourResult[i-1].s.lat,tourResult[i-1].s.lon],[o.s.lat,o.s.lon]):o.d),0);
  const due=tourResult.filter(o=>daysTo(o.s.nextVisit)<0).length, h=(tourResult.length*0.75+km/55).toFixed(1);
  document.getElementById('tourRecap').innerHTML=tourResult.length
    ?`<b>${tourResult.length} borne${tourResult.length>1?'s':''}</b> à visiter autour de <b>${cname}</b> dans un rayon de ${rad} km, dont la maintenance est due sous ${win>=9999?'n\'importe quelle échéance':win+' jours'}${due?` — <span style="color:var(--err);font-weight:700">dont ${due} déjà en retard</span>`:''}. Itinéraire ≈ <b>${Math.round(km)} km</b> · ${h} h.`
    :`Aucune borne autour de <b>${cname}</b> dans ${rad} km avec une maintenance due sous ${win} jours. Augmentez la distance ou l'échéance.`;
  document.getElementById('tourStats').innerHTML=[
    statCard('Bornes à visiter',tourResult.length,'🧭','dans '+rad+' km',''),
    statCard('Trajet estimé',Math.round(km)+' km','🛣️','ordre par proximité',''),
    statCard('Temps estimé',h+' h','⏱️','≈45 min/borne + route',''),
  ].join('');
  document.querySelector('#tourTable tbody').innerHTML=tourResult.map((o,i)=>`<tr style="cursor:pointer" onclick="openStation('${o.s.id}')"><td><b>${i+1}</b></td><td>${o.s.name}<div class="muted" style="font-size:11px">${o.s.type} ${o.s.power} kW</div></td><td>${o.d.toFixed(1)} km</td><td>${fmtD(o.s.nextVisit)}<div class="muted" style="font-size:11px">${daysTo(o.s.nextVisit)} j</div></td><td><span class="tag" style="background:${PRIO_HEX[o.s.priority]}22;color:${PRIO_HEX[o.s.priority]}">${o.s.priority}</span></td><td><span class="st-dot ${STATE_CLASS[o.s.state]}" style="display:inline-block"></span></td></tr>`).join('')||'<tr><td colspan="6" style="text-align:center;color:var(--text-faint);padding:22px">Aucune borne — élargissez la distance ou l\'échéance.</td></tr>';
  drawTourMini();
}
function drawTourMini(){if(!tmap||!tourCenter)return;
  [tCircle,tMarkers,tCenterMk].forEach(l=>l&&tmap.removeLayer(l));
  tCircle=L.circle(tourCenter,{radius:tourRad*1000,color:'#157a5e',fillColor:'#1fae86',fillOpacity:.12,weight:2}).addTo(tmap);
  tCenterMk=L.marker(tourCenter).addTo(tmap).bindTooltip('Point de départ');
  tMarkers=L.layerGroup(tourResult.map((o,i)=>L.circleMarker([o.s.lat,o.s.lon],{radius:7,color:'#fff',weight:1.5,fillColor:PRIO_HEX[o.s.priority],fillOpacity:.95}).bindTooltip(`${i+1}. ${o.s.name} (${o.d.toFixed(1)} km)`))).addTo(tmap);
  try{tmap.fitBounds(tCircle.getBounds().pad(0.08));}catch(e){}
}
['tourCenter','tourRadius','tourWin'].forEach(id=>document.getElementById(id).onchange=runTournee);
document.getElementById('tourPlan').onclick=()=>{if(!tourResult.length){toast('Aucune borne à planifier');return;}tourResult.forEach(o=>TICKETS.unshift(mkTicket(o.s,'preventif','mineur','assigné',0,'préventif','Tournée préventive — '+o.s.city)));renderGMAO();updateCounts();toast(tourResult.length+' interventions préventives créées et affectées (tournée '+document.getElementById('tourCenter').value+')');};

/* ============ KPI ============ */
let kpiScope='net';const shortSta=n=>n.split('–')[0].split(' ')[0].trim();
const kpiTypeVal=()=>document.getElementById('kpiType').value;
const kpiBornes=()=>{const t=kpiTypeVal();return ALL_BORNES.filter(b=>(!t||b.type===t)&&(!selectedNet||b.net===selectedNet));};
function renderKPI(){document.getElementById('kpiNet').style.display=kpiScope==='net'?'':'none';document.getElementById('kpiBorne').style.display=kpiScope==='borne'?'':'none';document.getElementById('kpiMaint').style.display=kpiScope==='maint'?'':'none';
  if(kpiScope==='net')renderKPINet();else if(kpiScope==='borne')renderKPIBorne();else renderKPIMaint();}
function renderKPINet(){const bs=kpiBornes(),t=kpiTypeVal();const energy=bs.reduce((a,b)=>a+b.energy6m,0),sessions=bs.reduce((a,b)=>a+b.sessions6m,0),avail=(bs.reduce((a,b)=>a+b.avail,0)/bs.length).toFixed(1),co2=bs.reduce((a,b)=>a+b.co2,0);
  document.getElementById('kpiStats').innerHTML=[statCard('Disponibilité réseau',avail.replace('.',',')+' %','🟢','cible 99,5 %','down'),statCard('Énergie (6 mois)',(energy/1000).toFixed(0)+' MWh','⚡','+18 % vs N-1','up'),statCard('Sessions (6 mois)',sessions.toLocaleString('fr-FR'),'🔌','+9 %','up'),statCard('CO₂ évité',(co2/1000).toFixed(1)+' t','🌱','vs thermique','up')].join('');
  const mult=t==='DC'?.78:t==='AC'?.22:1;barChart('chartEnergy',['Jan','Fév','Mar','Avr','Mai','Jun'],[44,48,51,53,57,59].map(v=>Math.round(v*mult)),'#157a5e',' MWh');
  lineChart('chartAvail',['Jan','Fév','Mar','Avr','Mai','Jun'],[99.1,98.4,98.9,97.8,99.0,98.6]);donutChart('chartStatus');
  const dcE=ALL_BORNES.filter(b=>b.type==='DC').reduce((a,b)=>a+b.energy6m,0),acE=ALL_BORNES.filter(b=>b.type==='AC').reduce((a,b)=>a+b.energy6m,0);
  donutData('chartMix',[{label:'DC',value:dcE,color:'#6d28d9'},{label:'AC',value:acE,color:'#0e7490'}],'kWh');barChart('chartAge',['<2 ans','2-4','4-6','>6'],ageBuckets(),'#1fae86',' bornes');}
function renderKPIBorne(){const bs=kpiBornes();const avgUtil=Math.round(bs.reduce((a,b)=>a+b.util,0)/bs.length),avgE=Math.round(bs.reduce((a,b)=>a+b.energy6m,0)/bs.length),avgA=(bs.reduce((a,b)=>a+b.avail,0)/bs.length).toFixed(1),avgM=Math.round(bs.reduce((a,b)=>a+b.mtbf,0)/bs.length),defB=bs.filter(b=>b.state==='err'||b.state==='off').length;
  document.getElementById('borneStats').innerHTML=[statCard('Bornes',bs.length,'⚡','',''),statCard('Utilisation',avgUtil+' %','📈','moy.',''),statCard('Énergie/borne',(avgE/1000).toFixed(1)+' MWh','🔋','6 mois',''),statCard('Dispo. moy.',avgA.replace('.',',')+' %','🟢','','down'),statCard('MTBF moy.',avgM+' j','🛠️','',''),statCard('En défaut',defB,'⚠️','',defB?'down':'')].join('');
  const topE=bs.slice().sort((a,b)=>b.energy6m-a.energy6m).slice(0,10);hbarData('chartBorneEnergy',topE.map(b=>({label:`${shortSta(b.station)} ${b.name.replace('Borne ','B')}`,value:b.energy6m,color:b.type==='DC'?'#6d28d9':'#0e7490'})),' kWh');
  const topU=bs.slice().sort((a,b)=>b.util-a.util).slice(0,12);vbarData('chartBorneUtil',topU.map(b=>({label:b.name.replace('Borne ','B')+'·'+shortSta(b.station).slice(0,3),value:b.util,color:b.util>=40?'#16a34a':b.util>=25?'#1fae86':b.util>=15?'#f59e0b':'#ef4444'})),' %',25);
  const conn={};ALL_BORNES.forEach(b=>b.pdcs.forEach(p=>{conn[p.conn]=(conn[p.conn]||0)+p.energy6m;}));donutData('chartConn',Object.entries(conn).map(([k,v])=>({label:k,value:v,color:{'Combo CCS':'#6d28d9','CHAdeMO':'#0891b2','T2':'#0e7490'}[k]})),'kWh');
  scatterChart('chartReliab',bs.map(b=>({x:b.defaults6m,y:b.avail,r:Math.max(4,Math.sqrt(b.energy6m)/22),color:STATE_HEX[b.state],label:b.station})),Math.max(8,...bs.map(b=>b.defaults6m))+1,55,100,'Défauts / 6 mois');
  const topS=bs.slice().sort((a,b)=>b.avgSessionKwh-a.avgSessionKwh).slice(0,12);vbarData('chartSession',topS.map(b=>({label:b.name.replace('Borne ','B')+'·'+shortSta(b.station).slice(0,3),value:b.avgSessionKwh,color:b.type==='DC'?'#6d28d9':'#0e7490'})),' kWh');}
function renderKPIMaint(){const base=selectedNet?TICKETS.filter(t=>t.net===selectedNet):TICKETS;const closed=base.filter(t=>!isOpen(t));
  const gtrOk=closed.filter(t=>t.closedAt<=t.gtr).length,respect=closed.length?Math.round(gtrOk/closed.length*100):100;
  const mttr=Math.round(base.reduce((a,t)=>a+(t.crit==='critique'?12:t.crit==='majeur'?22:40),0)/base.length);
  document.getElementById('maintStats').innerHTML=[
    statCard('Tickets (12 m)',base.length,'🎫','',''),statCard('Backlog',base.filter(isOpen).length,'📥','ouverts',''),
    statCard('Respect GTR',respect+' %','⏱️','cible 95 %',respect<95?'down':'up'),statCard('MTTR',mttr+' h','🛠️','moy. réparation',''),
    statCard('MTBF',Math.round(ALL_BORNES.reduce((a,b)=>a+b.mtbf,0)/ALL_BORNES.length)+' j','🔧','entre pannes',''),
    statCard('Taux réouverture',(3+Math.random()*4).toFixed(1)+' %','↩️','',''),
  ].join('');
  lineChartPct('chartSla',['Jan','Fév','Mar','Avr','Mai','Jun'],[[96,94,97,93,98,95],[91,89,93,88,94,respect]]);
  barChart('chartBacklog',['Jan','Fév','Mar','Avr','Mai','Jun'],[18,22,17,25,20,base.filter(isOpen).length],'#f59e0b',' tickets');
  const fail={};base.forEach(t=>{const k=shortSta(t.station);fail[k]=(fail[k]||0)+1;});
  hbarData('chartTopFail',Object.entries(fail).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([k,v])=>({label:k,value:v,color:'#ef4444'})),' tickets');
  const mix={};base.forEach(t=>{mix[t.crit]=(mix[t.crit]||0)+1;});donutData('chartTkMix',[{label:'Critique',value:mix.critique||0,color:'#ef4444'},{label:'Majeur',value:mix.majeur||0,color:'#f59e0b'},{label:'Mineur',value:mix.mineur||0,color:'#2563eb'}],'tickets');}
function ageBuckets(){const b=[0,0,0,0];ALL_BORNES.forEach(x=>{const a=x.age;if(a<2)b[0]++;else if(a<4)b[1]++;else if(a<6)b[2]++;else b[3]++;});return b;}

/* charts */
function svgFrame(id){const el=document.getElementById(id),w=el.clientWidth||520;el.innerHTML='';return{el,w};}
function barChart(id,labels,data,color,unit){const{el,w}=svgFrame(id),h=200,pad=30,max=Math.max(...data)*1.15||1,bw=(w-pad*2)/data.length*.62;let s=`<svg width="100%" viewBox="0 0 ${w} ${h}">`;[0,.25,.5,.75,1].forEach(t=>{const y=pad+(h-pad*1.6)*t;s+=`<line x1="${pad}" y1="${y}" x2="${w-10}" y2="${y}" stroke="#eef2f1"/>`;});data.forEach((d,i)=>{const x=pad+(i+.5)*(w-pad*2)/data.length,bh=(d/max)*(h-pad*1.6),y=h-pad*.6-bh;s+=`<rect x="${x-bw/2}" y="${y}" width="${bw}" height="${bh}" rx="4" fill="${color}"><title>${labels[i]}: ${d}${unit||''}</title></rect><text x="${x}" y="${y-6}" text-anchor="middle" font-size="11" font-weight="700" fill="#1b2b29">${d}</text><text x="${x}" y="${h-8}" text-anchor="middle" font-size="11" fill="#5a6b68">${labels[i]}</text>`;});el.innerHTML=s+'</svg>';}
function lineChart(id,labels,data){const{el,w}=svgFrame(id),h=200,pad=34,min=96,max=100,X=i=>pad+i*(w-pad*1.3)/(data.length-1),Y=v=>pad+(1-(v-min)/(max-min))*(h-pad*1.8);let s=`<svg width="100%" viewBox="0 0 ${w} ${h}">`;[96,97,98,99,100].forEach(v=>{const y=Y(v);s+=`<line x1="${pad}" y1="${y}" x2="${w-10}" y2="${y}" stroke="#eef2f1"/><text x="6" y="${y+3}" font-size="10" fill="#8a9794">${v}%</text>`;});const yT=Y(99.5);s+=`<line x1="${pad}" y1="${yT}" x2="${w-10}" y2="${yT}" stroke="#16a34a" stroke-dasharray="4 4"/>`;const pts=data.map((d,i)=>`${X(i)},${Y(d)}`).join(' ');s+=`<polyline points="${pts}" fill="none" stroke="#157a5e" stroke-width="2.5"/>`;data.forEach((d,i)=>{s+=`<circle cx="${X(i)}" cy="${Y(d)}" r="4" fill="#fff" stroke="#157a5e" stroke-width="2.5"><title>${labels[i]}: ${d}%</title></circle><text x="${X(i)}" y="${h-8}" text-anchor="middle" font-size="11" fill="#5a6b68">${labels[i]}</text>`;});el.innerHTML=s+'</svg>';}
function lineChartPct(id,labels,series){const{el,w}=svgFrame(id),h=200,pad=34,min=80,max=100,cols=['#157a5e','#f59e0b'],names=['GTI','GTR'],X=i=>pad+i*(w-pad*1.3)/(labels.length-1),Y=v=>pad+(1-(v-min)/(max-min))*(h-pad*1.8);let s=`<svg width="100%" viewBox="0 0 ${w} ${h}">`;[80,85,90,95,100].forEach(v=>{const y=Y(v);s+=`<line x1="${pad}" y1="${y}" x2="${w-10}" y2="${y}" stroke="#eef2f1"/><text x="4" y="${y+3}" font-size="10" fill="#8a9794">${v}%</text>`;});series.forEach((data,k)=>{const pts=data.map((d,i)=>`${X(i)},${Y(d)}`).join(' ');s+=`<polyline points="${pts}" fill="none" stroke="${cols[k]}" stroke-width="2.5"/>`;data.forEach((d,i)=>{s+=`<circle cx="${X(i)}" cy="${Y(d)}" r="3.5" fill="${cols[k]}"><title>${names[k]} ${labels[i]}: ${d}%</title></circle>`;});});labels.forEach((l,i)=>s+=`<text x="${X(i)}" y="${h-8}" text-anchor="middle" font-size="11" fill="#5a6b68">${l}</text>`);names.forEach((nm,k)=>s+=`<rect x="${w-110+k*55}" y="8" width="10" height="10" fill="${cols[k]}"/><text x="${w-96+k*55}" y="17" font-size="11" fill="#1b2b29">${nm}</text>`);el.innerHTML=s+'</svg>';}
function donutChart(id){const{el,w}=svgFrame(id),h=200,cx=w*.30,cy=h/2,r=64,ir=40,counts={ok:0,warn:0,err:0,off:0};(selectedNet?STATIONS.filter(s=>s.net===selectedNet):STATIONS).forEach(s=>counts[s.state]++);const cols={ok:'#16a34a',warn:'#f59e0b',err:'#ef4444',off:'#94a3b8'},tot=Object.values(counts).reduce((a,b)=>a+b,0)||1;let ang=-Math.PI/2,s=`<svg width="100%" viewBox="0 0 ${w} ${h}">`;Object.entries(counts).forEach(([k,v])=>{if(!v)return;const a2=ang+v/tot*2*Math.PI,lg=a2-ang>Math.PI?1:0,x1=cx+r*Math.cos(ang),y1=cy+r*Math.sin(ang),x2=cx+r*Math.cos(a2),y2=cy+r*Math.sin(a2),xi2=cx+ir*Math.cos(a2),yi2=cy+ir*Math.sin(a2),xi1=cx+ir*Math.cos(ang),yi1=cy+ir*Math.sin(ang);s+=`<path d="M${x1} ${y1} A${r} ${r} 0 ${lg} 1 ${x2} ${y2} L${xi2} ${yi2} A${ir} ${ir} 0 ${lg} 0 ${xi1} ${yi1} Z" fill="${cols[k]}"><title>${STATE_LABEL[k]}: ${v}</title></path>`;ang=a2;});s+=`<text x="${cx}" y="${cy-2}" text-anchor="middle" font-size="20" font-weight="800">${tot}</text><text x="${cx}" y="${cy+15}" text-anchor="middle" font-size="11" fill="#5a6b68">stations</text>`;let lx=w*.56,ly=44;Object.entries(counts).forEach(([k,v])=>{s+=`<rect x="${lx}" y="${ly-9}" width="11" height="11" rx="2" fill="${cols[k]}"/><text x="${lx+17}" y="${ly}" font-size="11.5">${STATE_LABEL[k]} (${v})</text>`;ly+=23;});el.innerHTML=s+'</svg>';}
function donutData(id,segs,unit){const{el,w}=svgFrame(id),h=200,cx=w*.30,cy=h/2,r=64,ir=40,tot=segs.reduce((a,s)=>a+s.value,0)||1;let ang=-Math.PI/2,s=`<svg width="100%" viewBox="0 0 ${w} ${h}">`;segs.forEach(sg=>{if(!sg.value)return;const a2=ang+sg.value/tot*2*Math.PI,lg=a2-ang>Math.PI?1:0,x1=cx+r*Math.cos(ang),y1=cy+r*Math.sin(ang),x2=cx+r*Math.cos(a2),y2=cy+r*Math.sin(a2),xi2=cx+ir*Math.cos(a2),yi2=cy+ir*Math.sin(a2),xi1=cx+ir*Math.cos(ang),yi1=cy+ir*Math.sin(ang);s+=`<path d="M${x1} ${y1} A${r} ${r} 0 ${lg} 1 ${x2} ${y2} L${xi2} ${yi2} A${ir} ${ir} 0 ${lg} 0 ${xi1} ${yi1} Z" fill="${sg.color}"><title>${sg.label}: ${Math.round(sg.value).toLocaleString('fr-FR')} ${unit}</title></path>`;ang=a2;});let lx=w*.56,ly=cy-segs.length*12+8;segs.forEach(sg=>{s+=`<rect x="${lx}" y="${ly-9}" width="11" height="11" rx="2" fill="${sg.color}"/><text x="${lx+17}" y="${ly}" font-size="11.5">${sg.label} · ${Math.round(sg.value/tot*100)}%</text>`;ly+=24;});el.innerHTML=s+'</svg>';}
function hbarData(id,items,unit){const{el,w}=svgFrame(id),h=Math.max(180,items.length*25+12),pad=130,max=Math.max(...items.map(i=>i.value))||1;let s=`<svg width="100%" viewBox="0 0 ${w} ${h}">`;items.forEach((d,i)=>{const y=10+i*((h-14)/items.length),bw=(d.value/max)*(w-pad-64);s+=`<text x="${pad-8}" y="${y+13}" text-anchor="end" font-size="11" fill="#1b2b29">${d.label}</text><rect x="${pad}" y="${y}" width="${Math.max(2,bw)}" height="16" rx="4" fill="${d.color}"><title>${d.label}: ${d.value}${unit}</title></rect><text x="${pad+Math.max(2,bw)+6}" y="${y+13}" font-size="10.5" font-weight="700" fill="#5a6b68">${d.value.toLocaleString('fr-FR')}</text>`;});el.innerHTML=s+'</svg>';}
function vbarData(id,items,unit,target){const{el,w}=svgFrame(id),h=210,pad=26,max=Math.max(...items.map(i=>i.value),target||0)*1.18||1,bw=(w-pad*2)/items.length*.62;let s=`<svg width="100%" viewBox="0 0 ${w} ${h}">`;[0,.5,1].forEach(t=>{const y=pad+(h-pad*2.4)*t;s+=`<line x1="${pad}" y1="${y}" x2="${w-6}" y2="${y}" stroke="#eef2f1"/>`;});if(target){const ty=h-pad*1.3-(target/max)*(h-pad*2.4);s+=`<line x1="${pad}" y1="${ty}" x2="${w-6}" y2="${ty}" stroke="#94a3b8" stroke-dasharray="4 4"/><text x="${w-6}" y="${ty-4}" text-anchor="end" font-size="10" fill="#8a9794">cible ${target}${unit}</text>`;}items.forEach((d,i)=>{const x=pad+(i+.5)*(w-pad*2)/items.length,bh=(d.value/max)*(h-pad*2.4),y=h-pad*1.3-bh;s+=`<rect x="${x-bw/2}" y="${y}" width="${bw}" height="${Math.max(1,bh)}" rx="3" fill="${d.color}"><title>${d.label}: ${d.value}${unit}</title></rect><text x="${x}" y="${y-4}" text-anchor="middle" font-size="9.5" font-weight="700">${d.value}</text><text x="${x}" y="${h-6}" text-anchor="middle" font-size="8" fill="#5a6b68">${d.label}</text>`;});el.innerHTML=s+'</svg>';}
function scatterChart(id,pts,xMax,yMin,yMax,xLabel){const{el,w}=svgFrame(id),h=210,padL=32,padB=26,padT=10,padR=10,X=v=>padL+(v/xMax)*(w-padL-padR),Y=v=>padT+(1-(v-yMin)/(yMax-yMin))*(h-padT-padB);let s=`<svg width="100%" viewBox="0 0 ${w} ${h}">`;for(let g=yMin;g<=yMax;g+=(yMax-yMin)/4){const y=Y(g);s+=`<line x1="${padL}" y1="${y}" x2="${w-padR}" y2="${y}" stroke="#eef2f1"/><text x="4" y="${y+3}" font-size="9" fill="#8a9794">${Math.round(g)}</text>`;}for(let g=0;g<=xMax;g+=Math.max(1,Math.ceil(xMax/5))){const x=X(g);s+=`<text x="${x}" y="${h-9}" text-anchor="middle" font-size="9" fill="#8a9794">${g}</text>`;}pts.forEach(p=>{s+=`<circle cx="${X(p.x)}" cy="${Y(p.y)}" r="${p.r}" fill="${p.color}" fill-opacity=".5" stroke="${p.color}" stroke-width="1.2"><title>${p.label} — ${p.y}% · ${p.x} défaut(s)</title></circle>`;});s+=`<text x="${(w+padL)/2}" y="${h}" text-anchor="middle" font-size="9.5" fill="#5a6b68">${xLabel}</text>`;el.innerHTML=s+'</svg>';}

