function renderConnect(){document.getElementById('connectGrid').innerHTML=CONNECTORS.map(c=>`<div class="card" style="padding:16px 18px"><div style="display:flex;justify-content:space-between"><div style="font-size:22px">🔌</div><span class="tag ${c.ok?'t-ok':'t-off'}">${c.status}</span></div><h3 style="font-size:15px;margin-top:8px">${c.name}</h3><div class="muted" style="font-size:12.5px;margin-top:3px">${c.type} · ${c.proto}</div><p style="font-size:12.5px;color:var(--text-soft);margin-top:9px">${c.detail}</p><div style="display:flex;justify-content:space-between;align-items:center;margin-top:12px"><button class="btn ghost sm">Configurer</button>${c.lastTx?`<span style="display:inline-flex;flex-direction:column;align-items:flex-end;gap:1px"><span style="font-size:11px;color:var(--text-soft)">Dernière transmission</span><span style="font-size:11.5px;font-weight:600;color:var(--text)">${c.lastTx}</span></span>`:''}</div></div>`).join('');}
async function loadAdminUsers(){
  if(currentUser&&getUserCaps(currentUser).manageUsers){
    const{data,error}=await _sb.from('profiles').select('*').order('name');
    if(!error&&data)DB_USERS=data;
  }
  renderAdmin();
}
function renderAdmin(){
  document.querySelector('#tenantTable tbody').innerHTML=TENANTS.map(t=>`<tr><td><b>${t.name}</b></td><td><span class="chip">${t.volume}</span></td><td>${t.sta}</td><td>${t.users}</td><td><span class="tag ${t.status==='Actif'?'t-ok':'t-info'}">${t.status}</span></td></tr>`).join('');
  const canMgr=currentUser&&getUserCaps(currentUser).manageUsers;
  const rows=(DB_USERS.length?DB_USERS:USERS).map(u=>{
    const nets=u.networks||[];
    const netLabel=nets.length?nets.map(id=>`<span class="chip" style="margin:1px">${id}</span>`).join(''):`<span class="muted" style="font-size:11px">Tous</span>`;
    const hasMaint=(u.modules||{}).maintenance!==false;
    const ini=u.initials||(u.name||'').split(' ').map(x=>x[0]).join('').slice(0,2).toUpperCase()||'?';
    return `<tr><td><div style="display:flex;align-items:center;gap:8px"><span class="avatar" style="width:26px;height:26px;font-size:10px">${ini}</span><div><b>${u.name||''}</b><div class="muted" style="font-size:11px">${u.email||''}</div></div></div></td><td>${u.role||''}</td><td>${netLabel}</td><td>${hasMaint?'<span class="tag t-ok">✓</span>':'<span class="tag t-off">—</span>'}</td><td>${canMgr&&u.id?`<button class="btn ghost sm" onclick="openEditUser('${u.id}')">✏️ Droits</button>`:''}</td></tr>`;
  }).join('');
  document.querySelector('#userTable tbody').innerHTML=rows;
  const addBtn=document.getElementById('btnAddUser');if(addBtn)addBtn.style.display=canMgr?'':'none';
  document.querySelector('#techTable tbody').innerHTML=TECHS.map(t=>`<tr><td><b>${t.name}</b></td><td>${t.type}</td><td>${t.comp.map(c=>`<span class="chip" style="margin:1px">${c}</span>`).join('')}</td><td class="muted">${t.hab}</td><td>${t.zone}</td><td><div class="pbar" style="width:90px"><div style="width:${t.load}%;background:${t.load>75?'var(--err)':t.load>55?'var(--warn)':'var(--ok)'}"></div></div><span class="muted" style="font-size:11px">${t.load}%</span></td></tr>`).join('');
  document.getElementById('rbacTable').innerHTML='<thead><tr>'+RBAC_ROLES.map(r=>`<th>${r}</th>`).join('')+'</tr></thead><tbody>'+RBAC.map(row=>'<tr>'+row.map((c,i)=>i===0?`<td>${c}</td>`:`<td class="${c?'yes':'no'}">${c?'✓':'—'}</td>`).join('')+'</tr>').join('')+'</tbody>';
}
function renderAudit(){document.querySelector('#auditTable tbody').innerHTML=AUDIT.map(a=>`<tr><td class="muted">${a[0]}</td><td><b>${a[1]}</b></td><td>${a[2]}</td><td class="muted">${a[3]}</td><td class="muted">${a[4]}</td></tr>`).join('');}
const SEV_TAG={critique:'t-err',majeure:'t-warn',mineure:'t-info'};
function renderAlarmRules(){document.querySelector('#alarmTable tbody').innerHTML=ALARM_RULES.map(r=>`<tr><td><b>${r.champ}</b></td><td>${r.op}</td><td>${r.seuil}</td><td><span class="tag ${SEV_TAG[r.sev]}">${r.sev}</span></td><td>${r.act}</td><td><span class="tag t-ok">activée</span></td></tr>`).join('');}
document.getElementById('btnAlarmRule').onclick=()=>openModal('Nouvelle règle d\'alarme',`
  <div class="field"><label>Critère</label><select><option>Indisponibilité PDC</option><option>Perte communication OCPP</option><option>Énergie journalière</option><option>Taux de disponibilité</option><option>Firmware obsolète</option><option>Prochaine visite</option><option>Température module</option></select></div>
  <div style="display:grid;grid-template-columns:90px 1fr;gap:14px"><div class="field"><label>Opérateur</label><select><option>></option><option><</option><option>=</option><option>≠</option></select></div><div class="field"><label>Seuil</label><input placeholder="ex. 30 min, 0 kWh, oui…"></div></div>
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px"><div class="field"><label>Sévérité</label><select><option>critique</option><option>majeure</option><option>mineure</option></select></div><div class="field"><label>Action automatique</label><select><option>Créer ticket + notifier</option><option>Créer ticket</option><option>Notifier exploitant</option><option>Ajouter à l'échéancier</option></select></div></div>`,
  `<button class="btn ghost" onclick="closeModal()">Annuler</button><button class="btn" onclick="closeModal();toast('Règle d\\'alarme créée (paramétrable)')">Enregistrer</button>`,'');

/* ============ NOTIFICATIONS ============ */
function buildNotifs(){NOTIFS.length=0;document.getElementById('bellBadge').textContent=0;document.getElementById('notifPop').innerHTML='<h4>Notifications</h4><div class="notif"><div style="color:var(--text-faint);font-size:13px;padding:8px 0">Aucune notification.</div></div>';}
document.getElementById('bell').onclick=e=>{e.stopPropagation();document.getElementById('notifPop').classList.toggle('open');};
document.addEventListener('click',e=>{if(!e.target.closest('#notifPop')&&!e.target.closest('#bell'))document.getElementById('notifPop').classList.remove('open');});

/* ============ MODAL / TOAST ============ */
function openModal(title,body,foot,wide){document.getElementById('modal').className='modal'+(wide==='wide'?' wide':'');document.getElementById('modal').innerHTML=`<div class="modal-head">${title}<button class="x" onclick="closeModal()">✕</button></div><div class="modal-body">${body}</div><div class="modal-foot">${foot}</div>`;document.getElementById('overlay').classList.add('open');}
function closeModal(){document.getElementById('overlay').classList.remove('open');}
window.closeModal=closeModal;
document.getElementById('overlay').onclick=e=>{if(e.target.id==='overlay')closeModal();};
let toastT;function toast(msg){const el=document.getElementById('toast');el.textContent=msg;el.classList.add('show');clearTimeout(toastT);toastT=setTimeout(()=>el.classList.remove('show'),2600);}

/* ============ TENANT / COUNTS ============ */
const tenantSel=document.getElementById('tenantSel');
tenantSel.innerHTML='<option value="">Tous les réseaux</option>'+NETWORKS.map(n=>`<option value="${n.id}">${n.name} — ${n.region}</option>`).join('');
function updateCounts(){const sList=selectedNet?STATIONS.filter(s=>s.net===selectedNet):STATIONS;document.getElementById('cntStations').textContent=sList.length;document.getElementById('cntTickets').textContent=(selectedNet?TICKETS.filter(t=>t.net===selectedNet):TICKETS).filter(isOpen).length;document.getElementById('cntEch').textContent=(selectedNet?ECHEANCES.filter(e=>e.net===selectedNet):ECHEANCES).filter(e=>e.status!=='à venir').length;}
tenantSel.onchange=e=>{selectedNet=e.target.value;selectedId=null;drawer.classList.remove('open');
  renderMap();fitToSelection();renderRefTree();renderGedTree();renderGMAO();renderEch();renderStations();updateCounts();if(document.getElementById('view-kpi').classList.contains('active'))renderKPI();if(document.getElementById('view-planning').classList.contains('active'))renderAgenda();};

/* KPI scope */
document.querySelectorAll('#kpiScope [data-ks]').forEach(b=>b.onclick=()=>{document.querySelectorAll('#kpiScope [data-ks]').forEach(x=>x.classList.remove('on'));b.classList.add('on');kpiScope=b.dataset.ks;renderKPI();});
document.getElementById('kpiType').onchange=renderKPI;document.getElementById('kpiPeriod').onchange=renderKPI;

/* ============ LOGIN ============ */
function applyRBAC(){
  if(!currentUser)return;
  const caps=getUserCaps(currentUser);
  document.querySelectorAll('.nav-item[data-view]').forEach(b=>{b.style.display=caps.nav.includes(b.dataset.view)?'':'none';});
  document.getElementById('topAvatar').textContent=currentUser.initials||currentUser.name.slice(0,2).toUpperCase();
  document.getElementById('roleBadge').textContent=currentUser.role;
  document.getElementById('btnLogout').style.display='';
  const show=(id,v)=>{const el=document.getElementById(id);if(el)el.style.display=v?'':'none';};
  show('btnExport',caps.export);show('btnNewTk',caps.newTicket);show('btnPlanNew',caps.plan);show('tourPlan',caps.plan);show('btnAlarmRule',caps.manageUsers);show('btnAddUser',caps.manageUsers);
  const allowed=caps.networks;
  document.querySelectorAll('#tenantSel option').forEach(opt=>{if(!opt.value)return;opt.style.display=(!allowed.length||allowed.includes(opt.value))?'':'none';});
}
function doLogin(){
  document.getElementById('login').classList.add('hide');
  applyRBAC();
  const caps=getUserCaps(currentUser);
  const sel=document.getElementById('tenantSel');
  if(caps.networks.length===1){sel.value=caps.networks[0];sel.dispatchEvent(new Event('change'));}
  else if(currentUser.tenant){sel.value=currentUser.tenant;sel.dispatchEvent(new Event('change'));}
  setTimeout(()=>lmap.invalidateSize(),120);
  const now=new Date();AUDIT.unshift([now.toLocaleString('fr-FR'),currentUser.name,'Connexion réussie (Supabase Auth)','—','—']);
  renderAudit();loadAdminUsers();toast('Bienvenue, '+currentUser.name+' — '+currentUser.role);
}
async function fetchProfileAndLogin(sbUser){
  const{data:profile,error}=await _sb.from('profiles').select('*').eq('id',sbUser.id).single();
  if(error||!profile){document.getElementById('loginErr').style.display='block';document.getElementById('loginErr').textContent='Profil introuvable. Contactez l\'administrateur.';return;}
  currentUser={id:sbUser.id,email:sbUser.email,name:profile.name,role:profile.role,initials:profile.initials||profile.name.slice(0,2).toUpperCase(),tenant:profile.tenant||'',networks:profile.networks||[],modules:profile.modules||{}};
  doLogin();
}
document.getElementById('loginBtn').onclick=async()=>{
  const email=document.getElementById('loginEmail').value.trim();
  const pwd=document.getElementById('loginPwd').value;
  const errEl=document.getElementById('loginErr');
  const btn=document.getElementById('loginBtn');
  errEl.style.display='none';btn.disabled=true;btn.textContent='Connexion…';
  const{data,error}=await _sb.auth.signInWithPassword({email,password:pwd});
  btn.disabled=false;btn.textContent='Se connecter';
  if(error){errEl.style.display='block';errEl.textContent='Email ou mot de passe incorrect.';return;}
  await fetchProfileAndLogin(data.user);
};
document.getElementById('forgotLnk').onclick=()=>{
  document.getElementById('loginStep1').style.display='none';
  document.getElementById('loginStep3').style.display='block';
  document.getElementById('resetEmail').value=document.getElementById('loginEmail').value.trim();
  document.getElementById('resetMsg').style.display='none';
  document.getElementById('resetBtn').disabled=false;
  document.getElementById('resetBtn').textContent='Envoyer le lien';
};
document.getElementById('backToLoginLnk').onclick=()=>{
  document.getElementById('loginStep3').style.display='none';
  document.getElementById('loginStep1').style.display='block';
};
function showStep(n){['loginStep1','loginStep2','loginStep3','loginStep4'].forEach((id,i)=>{document.getElementById(id).style.display=(i===n-1)?'block':'none';});}
document.getElementById('signupLnk').onclick=()=>{
  showStep(4);
  document.getElementById('su_email').value=document.getElementById('loginEmail').value.trim();
  document.getElementById('suMsg').style.display='none';
  document.getElementById('suBtn').style.display='';
};
document.getElementById('backFromSignupLnk').onclick=()=>showStep(1);
document.getElementById('suBtn').onclick=async()=>{
  const name=document.getElementById('su_name').value.trim();
  const email=document.getElementById('su_email').value.trim();
  const pwd=document.getElementById('su_pwd').value;
  const pwd2=document.getElementById('su_pwd2').value;
  const msgEl=document.getElementById('suMsg');
  const btn=document.getElementById('suBtn');
  const err=(t)=>{msgEl.style.display='block';msgEl.style.background='#fee2e2';msgEl.style.color='var(--err)';msgEl.textContent=t;};
  if(!name||!email||!pwd){err('Tous les champs sont obligatoires.');return;}
  if(pwd.length<8){err('Le mot de passe doit contenir au moins 8 caractères.');return;}
  if(pwd!==pwd2){err('Les mots de passe ne correspondent pas.');return;}
  btn.disabled=true;btn.textContent='Création…';
  const{error}=await _sb.auth.signUp({email,password:pwd,options:{data:{name},emailRedirectTo:'https://nolannk3d.github.io/SIG-load-view/'}});
  btn.disabled=false;btn.textContent='Créer mon compte';
  if(error){err('Erreur : '+error.message);return;}
  msgEl.style.display='block';msgEl.style.background='#dcfce7';msgEl.style.color='#166534';
  msgEl.textContent='✓ Compte créé ! Vérifiez votre e-mail pour confirmer votre adresse, puis connectez-vous.';
  btn.style.display='none';
};
document.getElementById('resetBtn').onclick=async()=>{
  const email=document.getElementById('resetEmail').value.trim();
  const msgEl=document.getElementById('resetMsg');
  const btn=document.getElementById('resetBtn');
  if(!email){msgEl.style.display='block';msgEl.style.background='#fee2e2';msgEl.style.color='var(--err)';msgEl.textContent='Veuillez saisir votre adresse e-mail.';return;}
  btn.disabled=true;btn.textContent='Envoi…';
  const{error}=await _sb.auth.resetPasswordForEmail(email,{redirectTo:'https://nolannk3d.github.io/SIG-load-view/'});
  btn.disabled=false;btn.textContent='Envoyer le lien';
  if(error){msgEl.style.display='block';msgEl.style.background='#fee2e2';msgEl.style.color='var(--err)';msgEl.textContent='Erreur : '+error.message;return;}
  msgEl.style.display='block';msgEl.style.background='#dcfce7';msgEl.style.color='#166534';
  msgEl.textContent='✓ E-mail envoyé ! Vérifiez votre boîte mail (et les spams).';
  btn.style.display='none';
};
document.getElementById('mfaBtn').onclick=async()=>{
  const{data:{session}}=await _sb.auth.getSession();
  if(session)await fetchProfileAndLogin(session.user);
};
document.getElementById('btnLogout').onclick=async()=>{
  await _sb.auth.signOut();
  currentUser=null;
  document.getElementById('login').classList.remove('hide');
  document.getElementById('loginStep1').style.display='block';
  document.getElementById('loginStep2').style.display='none';
  document.getElementById('loginErr').style.display='none';
  document.querySelectorAll('.nav-item[data-view]').forEach(b=>b.style.display='');
  document.getElementById('btnLogout').style.display='none';
  document.querySelector('[data-view="map"]').click();
};
/* Restaurer la session au rechargement de la page */
_sb.auth.getSession().then(async({data:{session}})=>{
  if(session){await fetchProfileAndLogin(session.user);}
});
window.openEditUser=function(profileId){
  const u=DB_USERS.find(x=>x.id===profileId)||{};
  const nets=u.networks||[];
  const mods=u.modules||{};
  const netChecks=NETWORKS.map(n=>`<label class="check" style="padding:3px 0"><input type="checkbox" class="eu_net" value="${n.id}"${nets.includes(n.id)?' checked':''}> <b>${n.id}</b> — ${n.name} <span class="muted">(${n.region})</span></label>`).join('');
  const mc=(key,def=true)=>mods[key]!==undefined?mods[key]:def;
  openModal(`Droits — ${u.name||'Utilisateur'}`,`
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:24px">
      <div>
        <div class="field"><label>Rôle de base</label><select id="eu_role">${Object.keys(ROLE_CAPS).map(r=>`<option${r===u.role?' selected':''}>${r}</option>`).join('')}</select></div>
        <div style="margin-top:16px"><div style="font-weight:600;font-size:12px;color:var(--text-soft);text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px">Réseaux autorisés</div>
        <div style="font-size:11.5px;color:var(--text-faint);margin-bottom:8px">Aucune sélection = tous les réseaux</div>
        ${netChecks}</div>
      </div>
      <div>
        <div style="font-weight:600;font-size:12px;color:var(--text-soft);text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px">Modules</div>
        <label class="check"><input type="checkbox" id="eu_maintenance"${mc('maintenance')?' checked':''}> 🔧 Maintenance (GMAO, Planning, Tournées)</label>
        <label class="check"><input type="checkbox" id="eu_ged"${mc('ged')?' checked':''}> 📁 Gestion documentaire</label>
        <label class="check"><input type="checkbox" id="eu_kpi"${mc('kpi')?' checked':''}> 📊 Indicateurs KPI</label>
        <label class="check"><input type="checkbox" id="eu_connect"${mc('connect')?' checked':''}> 🔌 Connecteurs</label>
        <label class="check"><input type="checkbox" id="eu_admin"${mc('admin')?' checked':''}> ⚙️ Administration</label>
        <label class="check"><input type="checkbox" id="eu_audit"${mc('audit')?' checked':''}> 📋 Audit</label>
        <div style="font-weight:600;font-size:12px;color:var(--text-soft);text-transform:uppercase;letter-spacing:.05em;margin:14px 0 8px">Capacités</div>
        <label class="check"><input type="checkbox" id="eu_export"${mc('export')?' checked':''}> 📤 Export de données</label>
        <label class="check"><input type="checkbox" id="eu_newTicket"${mc('newTicket')?' checked':''}> 🎫 Créer des tickets</label>
      </div>
    </div>`,
    `<button class="btn ghost" onclick="closeModal()">Annuler</button><button class="btn" onclick="saveEditUser('${profileId}')">Enregistrer</button>`,'wide');
};
window.saveEditUser=async function(profileId){
  const role=document.getElementById('eu_role').value;
  const networks=[...document.querySelectorAll('.eu_net:checked')].map(cb=>cb.value);
  const modules={
    maintenance:document.getElementById('eu_maintenance').checked,
    ged:document.getElementById('eu_ged').checked,
    kpi:document.getElementById('eu_kpi').checked,
    connect:document.getElementById('eu_connect').checked,
    admin:document.getElementById('eu_admin').checked,
    audit:document.getElementById('eu_audit').checked,
    export:document.getElementById('eu_export').checked,
    newTicket:document.getElementById('eu_newTicket').checked,
  };
  const{error}=await _sb.from('profiles').update({role,networks,modules}).eq('id',profileId);
  if(error){toast('Erreur Supabase : '+error.message);return;}
  closeModal();await loadAdminUsers();toast('Droits mis à jour');
};
window.openAddUser=function(){
  openModal('Inviter un utilisateur',`
    <div class="field"><label>Nom complet</label><input id="nu_name" placeholder="Prénom Nom"></div>
    <div class="field"><label>E-mail</label><input id="nu_email" type="email" placeholder="email@domaine.com"></div>
    <div class="field"><label>Mot de passe provisoire</label><input id="nu_pwd" type="text" placeholder="MotDePasse123!"></div>
    <div class="field"><label>Rôle initial</label><select id="nu_role">${Object.keys(ROLE_CAPS).map(r=>`<option>${r}</option>`).join('')}</select></div>
    <div id="nu_msg" style="display:none;font-size:12.5px;padding:7px 10px;border-radius:7px;margin-top:8px"></div>`,
    `<button class="btn ghost" onclick="closeModal()">Annuler</button><button class="btn" id="nu_btn" onclick="saveNewUser()">Créer</button>`,'');
};
window.saveNewUser=async function(){
  const name=document.getElementById('nu_name').value.trim();
  const email=document.getElementById('nu_email').value.trim();
  const pwd=document.getElementById('nu_pwd').value;
  const role=document.getElementById('nu_role').value;
  const msgEl=document.getElementById('nu_msg');
  const btn=document.getElementById('nu_btn');
  if(!name||!email||!pwd){toast('Nom, e-mail et mot de passe requis');return;}
  btn.disabled=true;btn.textContent='Création…';
  const{data,error}=await _sb.auth.signUp({email,password:pwd,options:{data:{name,role},emailRedirectTo:'https://nolannk3d.github.io/SIG-load-view/'}});
  btn.disabled=false;btn.textContent='Créer';
  if(error){msgEl.style.cssText='display:block;background:#fee2e2;color:var(--err)';msgEl.textContent='Erreur : '+error.message;return;}
  if(data.user)await _sb.from('profiles').update({role}).eq('id',data.user.id);
  msgEl.style.cssText='display:block;background:#dcfce7;color:#166534';
  msgEl.textContent='✓ Compte créé. L\'utilisateur doit confirmer son e-mail. Vous pourrez ensuite modifier ses droits via ✏️';
  btn.style.display='none';
  setTimeout(()=>{closeModal();loadAdminUsers();},3000);
};
document.getElementById('btnAddUser').onclick=openAddUser;
document.querySelector('[data-view="admin"]').addEventListener('click',()=>{if(currentUser)loadAdminUsers();});

